package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.OpdrachtGroepCriterium;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.comparator.OpdrachtComparator;
import be.schaubroeck.lpb.tools.enumtypes.GewWrkwBv;
import be.schaubroeck.lpb.tools.exception.MessageException;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.TreeSet;

public class OpdrachtenGroepBuilder {

    //Zet alle BVcumul opdrachten bij elkander, en alle ander regimes op hun eigen eiland
    public static class BvcumulGewoneBezoldigingCriterium implements OpdrachtGroepCriterium {

        public static final BvcumulGewoneBezoldigingCriterium INSTANCE = new BvcumulGewoneBezoldigingCriterium();

        @Override
        public Integer getGroepKey(Opdracht opdracht, RekenTijd rekenTijd) {
            Integer sleutel;
            Opper laatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
            GewWrkwBv fiscaleWerkwijze = laatsteGegevens.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();
            if (fiscaleWerkwijze == GewWrkwBv.BAREMA_KUMUL && !WerknemersKengetalFactory.isStudent(laatsteGegevens, RkmTijdperk.getTijdperk(rekenTijd))) {
                sleutel = 0;
            } else {
                sleutel = opdracht.getOpdrachtnr();
            }
            return sleutel;
        }

    }

    public static class OpdrachtGroep {

        private Set<Opdracht> opdrachten = new TreeSet<>(OpdrachtComparator.DEFAULT);
        private Integer sleutel;

        public OpdrachtGroep(Integer sleutel) {
            this.sleutel = sleutel;
        }

        public void addOpdracht(Opdracht opdracht) {
            opdrachten.add(opdracht);
        }

        public Set<Opdracht> getOpdrachten() {
            return opdrachten;
        }

        public Integer getSleutel() {
            return sleutel;
        }

        public void setSleutel(Integer sleutel) {
            this.sleutel = sleutel;
        }

        public GewWrkwBv getWerkwijzeGewoneBezoldiging() {
            GewWrkwBv fiscaleWerkwijze = null;
            if (!opdrachten.isEmpty()) {
                Opdracht paragon = opdrachten.iterator().next();
                Opper laatsteGegevens = RekenTools.getOpperLaatsteGegevens(paragon);
                fiscaleWerkwijze = laatsteGegevens.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();
            }
            return fiscaleWerkwijze;
        }

        public boolean uitzonderingJobStudent(RekenTijd rekenTijd) {
            boolean uitzondering = false;
            if (opdrachten.size() == 1) {
                Opdracht paragon = opdrachten.iterator().next();
                Opper laatsteGegevens = RekenTools.getOpperLaatsteGegevens(paragon);
                GewWrkwBv fiscaleWerkwijze = laatsteGegevens.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();
                boolean isStudent = WerknemersKengetalFactory.isStudent(laatsteGegevens, RkmTijdperk.getTijdperk(rekenTijd));
                uitzondering = isStudent && fiscaleWerkwijze != GewWrkwBv.PERCENTAGE && fiscaleWerkwijze != GewWrkwBv.BEDRAG;
            }
            return uitzondering;
        }

        public Opdracht getOpdracht() {
            if (opdrachten.size() != 1) {
                throw new MessageException("getOpdracht() aangeroepen maar OpdrachtGroep omvat meerdere opdrachten.");
            } else {
                return opdrachten.iterator().next();
            }
        }

    }

    public List<OpdrachtGroep> groepeer(Persoon persoon, OpdrachtGroepCriterium sleutel, RekenTijd rekenTijd) {
        Map<Integer, OpdrachtGroep> opdrachtGroepMap = new HashMap<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            Integer groepKey = sleutel.getGroepKey(opdracht, rekenTijd);
            OpdrachtGroep groep = opdrachtGroepMap.computeIfAbsent(groepKey, OpdrachtGroep::new);
            if (BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                groep.addOpdracht(opdracht);
            }
        }
        return new ArrayList<>(opdrachtGroepMap.values());
    }


}
